package cli

import (
	"encoding/json"
	"fmt"
	"net/http"
	"os"
	"strings"
	"time"

	"github.com/mvanhorn/printing-press-library/library/productivity/slack/internal/config"
	"github.com/spf13/cobra"
)

func newDoctorCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "doctor",
		Short: "Check CLI health",
		RunE: func(cmd *cobra.Command, args []string) error {
			report := map[string]any{}

			// Check config
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				report["config"] = fmt.Sprintf("error: %s", err)
			} else {
				report["config"] = "ok"
				report["config_path"] = cfg.Path
				report["base_url"] = cfg.BaseURL
			}

			// Check auth
			if cfg != nil {
				header := cfg.AuthHeader()
				if header == "" {
					report["auth"] = "not configured"
					report["auth_hint"] = "export SLACK_BOT_TOKEN=<your-key>"
				} else {
					report["auth"] = "configured"
					report["auth_source"] = cfg.AuthSource
				}
			}

			// Check auth environment variables
			authEnvChecked := 0
			authEnvSet := 0
			authEnvChecked++
			if os.Getenv("SLACK_BOT_TOKEN") != "" {
				authEnvSet++
			}
			authEnvChecked++
			if os.Getenv("SLACK_USER_TOKEN") != "" {
				authEnvSet++
			}
			if authEnvSet == 0 {
				report["env_vars"] = fmt.Sprintf("none set (checked %d)", authEnvChecked)
			} else {
				report["env_vars"] = fmt.Sprintf("%d/%d set", authEnvSet, authEnvChecked)
			}

			// Check API connectivity and validate credentials
			if cfg != nil && cfg.BaseURL != "" {
				httpClient := &http.Client{Timeout: 5 * time.Second}
				baseURL := strings.TrimRight(cfg.BaseURL, "/")

				// Step 1: Basic reachability (unauthenticated HEAD)
				headReq, _ := http.NewRequest("HEAD", baseURL, nil)
				headResp, headErr := httpClient.Do(headReq)
				apiReachable := false
				if headErr == nil {
					headResp.Body.Close()
					apiReachable = true
				}

				// If HEAD failed, try GET on common health endpoints
				if !apiReachable {
					for _, p := range []string{"/health", "/healthz", "/status", "/ping", ""} {
						healthResp, healthErr := httpClient.Get(baseURL + p)
						if healthErr != nil {
							continue
						}
						healthResp.Body.Close()
						apiReachable = true
						break
					}
				}

				if !apiReachable {
					report["api"] = fmt.Sprintf("unreachable: %s", headErr)
				} else {
					report["api"] = "reachable"
				}

				// Step 2: Validate credentials with Slack's auth.test endpoint
				authHeader := cfg.AuthHeader()
				if authHeader == "" {
					// No auth configured — skip credential validation
				} else if !apiReachable {
					report["credentials"] = "skipped (API unreachable)"
				} else {
					authReq, _ := http.NewRequest("POST", baseURL+"/auth.test", nil)
					authReq.Header.Set("Authorization", authHeader)
					authReq.Header.Set("User-Agent", "slack-pp-cli")
					authResp, authErr := httpClient.Do(authReq)
					if authErr != nil {
						report["credentials"] = "error: could not reach API"
					} else {
						defer authResp.Body.Close()
						var result struct {
							OK    bool   `json:"ok"`
							Error string `json:"error"`
						}
						if json.NewDecoder(authResp.Body).Decode(&result) == nil && result.OK {
							report["credentials"] = "valid"
						} else if result.Error != "" {
							report["credentials"] = fmt.Sprintf("invalid (%s)", result.Error)
						} else {
							report["credentials"] = fmt.Sprintf("invalid (HTTP %d)", authResp.StatusCode)
						}
					}
				}
			} else if cfg != nil && cfg.BaseURL == "" {
				report["api"] = "not configured (set base_url in config file)"
			}

			report["version"] = version

			if flags.asJSON {
				return flags.printJSON(cmd, report)
			}

			// Human-readable output with color
			w := cmd.OutOrStdout()
			checkKeys := []struct{ key, label string }{
				{"config", "Config"},
				{"auth", "Auth"},
				{"api", "API"},
				{"credentials", "Credentials"},
			}
			for _, ck := range checkKeys {
				v, ok := report[ck.key]
				if !ok {
					continue
				}
				s := fmt.Sprintf("%v", v)
				indicator := green("OK")
				if strings.Contains(s, "error") || strings.Contains(s, "not configured") || strings.Contains(s, "unreachable") || strings.Contains(s, "invalid") {
					indicator = red("FAIL")
				} else if strings.Contains(s, "not ") || strings.Contains(s, "skipped") || strings.Contains(s, "inferred") {
					indicator = yellow("WARN")
				}
				fmt.Fprintf(w, "  %s %s: %s\n", indicator, ck.label, s)
			}
			// Print info keys without status indicator
			for _, key := range []string{"config_path", "base_url", "auth_source", "version"} {
				if v, ok := report[key]; ok {
					fmt.Fprintf(w, "  %s: %v\n", key, v)
				}
			}
			// Print auth setup hints (indented under Auth line)
			if hint, ok := report["auth_hint"]; ok {
				fmt.Fprintf(w, "  hint: %v\n", hint)
			}
			return nil
		},
	}
}
